import React from 'react'

export const IndexPage = () => {
  return (
    <div className='IndexPage w-screen h-screen bg-repeat-x' 
    style={{
        backgroundImage:"url('./requiredfiles/wave.png')",
        backgroundPosition: "center bottom"
    }}>
        <div className="flex">
            <div className='pt-[20px] w-[50%] flex items-center'>
                <img className="pl-[20px]" src="./requiredfiles/Logo.png" width={"80px"} alt="" />
                <h1 className='text-[35px] font-["Sevillana", cursive]'>Secure Notes</h1>
            </div>
        </div>
    </div>
  )
}
